function parseCSV(raw) {
  if (!raw || !raw.trim()) return [];
  const lines = raw.trim().split('\n').map(l => l.replace(/\r$/,''));
  if (lines.length < 2) return [];
  const parseRow = line => {
    const vals = []; let cur = '', inQ = false;
    for (const ch of line + ',') {
      if (ch === '"') { inQ = !inQ; }
      else if (ch === ',' && !inQ) { vals.push(cur.trim()); cur = ''; }
      else cur += ch;
    }
    return vals;
  };
  const header = parseRow(lines[0]);
  return lines.slice(1).filter(l => l.trim()).map(l => {
    const vals = parseRow(l);
    const obj = {};
    header.forEach((h,i) => { obj[h] = vals[i] ?? ''; });
    return obj;
  });
}

const bottles = parseCSV($input.all()[0].json.data);
const notes   = parseCSV($input.all()[1].json.data);

const notesByWine = {};
for (const n of notes) {
  const id = n.iWine || n.iwine;
  if (!id) continue;
  if (!notesByWine[id]) notesByWine[id] = { texts: [], latestDate: null };
  if (n.Note && n.Note.trim()) notesByWine[id].texts.push(n.Note.trim());
  if (n.Date) {
    const d = new Date(n.Date);
    if (!notesByWine[id].latestDate || d > new Date(notesByWine[id].latestDate))
      notesByWine[id].latestDate = n.Date;
  }
}

const toInt   = v => v !== '' && !isNaN(parseInt(v,10))   ? parseInt(v,10)   : null;
const toFloat = v => v !== '' && !isNaN(parseFloat(v))    ? parseFloat(v)    : null;
const toStr   = v => v !== '' && v != null ? String(v).trim() : null;

const output = [];
for (const row of bottles) {
  const ibottle = row.iBottle || row.ibottle;
  const iwine   = row.iWine   || row.iwine;
  if (!ibottle) continue;
  const noteData = notesByWine[iwine] || { texts: [], latestDate: null };
  const my_notes = noteData.texts.length > 0 ? noteData.texts.join(' | ') : null;
  const parts = [
    toStr(row.Wine),
    toInt(row.Vintage) && row.Vintage !== '0' ? 'Vintage ' + row.Vintage : null,
    toStr(row.Producer), toStr(row.Type), toStr(row.Color), toStr(row.Category),
    toStr(row.Locale), toStr(row.Appellation), toStr(row.Region), toStr(row.Country),
    toStr(row.Location) ? 'Location: ' + row.Location : null,
    toStr(row.Bin) ? 'Bin: ' + row.Bin : null,
    toInt(row.BeginConsume) && toInt(row.EndConsume) ? 'Drink ' + row.BeginConsume + '-' + row.EndConsume : null,
    toFloat(row.CT) ? 'CellarTracker score ' + row.CT : null,
    toFloat(row.MyScore) ? 'My score ' + row.MyScore : null,
    toFloat(row.PurchasePrice) ? 'Purchased at $' + row.PurchasePrice : null,
    my_notes ? 'Tasting notes: ' + my_notes : null
  ].filter(Boolean);
  output.push({ json: {
    ct_ibottle: toInt(ibottle), ct_iwine: toInt(iwine),
    wine: toStr(row.Wine), vintage: toInt(row.Vintage),
    producer: toStr(row.Producer), wine_type: toStr(row.Type),
    color: toStr(row.Color), varietal: toStr(row.Category),
    appellation: toStr(row.Appellation), region: toStr(row.Region),
    country: toStr(row.Country), locale: toStr(row.Locale),
    location: toStr(row.Location), bin: toStr(row.Bin),
    purchase_price: toFloat(row.PurchasePrice), valuation: toFloat(row.Valuation),
    drink_from: toInt(row.BeginConsume), drink_to: toInt(row.EndConsume),
    ct_score: toFloat(row.CT), my_score: toFloat(row.MyScore),
    my_notes: my_notes, note_date: noteData.latestDate || null,
    removed_at: null, last_synced_at: new Date().toISOString(),
    raw_ct_row: JSON.stringify(row),
    embedding_text: parts.join('. ')
  }});
}
return output;

const oai  = $json;
const wine = $('Parse CSV + Merge Notes').item.json;
const embedding = oai && oai.data && oai.data[0] ? oai.data[0].embedding : null;
if (!embedding || !Array.isArray(embedding))
  throw new Error('No embedding for: ' + wine.wine + ' iBottle ' + wine.ct_ibottle);
const result = Object.assign({}, wine);
result.embedding = '[' + embedding.join(',') + ']';
delete result.embedding_text;
return { json: result };

const all = $input.all();
const activeBottles = Array.from(new Set(all.map(i => i.json.ct_ibottle).filter(Boolean)));
return [{ json: { active_bottles: activeBottles, count: activeBottles.length } }];

const upsertCount = $('Collect Active iBottle IDs').first().json.count;
const today = new Date().toISOString().slice(0,10);
const summary = 'Wine inventory sync ' + today + ': ' + upsertCount + ' bottles upserted from CellarTracker. Soft-delete sweep and purchase preference inference complete.';
return [{ json: { summary: summary } }];
